// --- Glob matching ---

/**
 * Minimal glob matcher supporting:
 *   **   any path segment(s) including none
 *   *    any characters within a single segment (no /)
 *   ?    any single character (no /)
 *   .    literal dot (escaped)
 */
function globToRegex(pattern: string): RegExp {
  // Escape special regex chars except our glob wildcards
  let regexStr = "";
  let i = 0;
  while (i < pattern.length) {
    const ch = pattern[i];
    if (ch === "*" && pattern[i + 1] === "*") {
      // ** matches any sequence including path separators
      // Allow leading/trailing slash around **
      regexStr += "(?:.+/|)";
      // skip optional trailing /
      i += 2;
      if (pattern[i] === "/") i++;
      continue;
    } else if (ch === "*") {
      // * matches anything except /
      regexStr += "[^/]*";
    } else if (ch === "?") {
      // ? matches any single char except /
      regexStr += "[^/]";
    } else if (".+^${}[]|()|\\".includes(ch)) {
      // Escape regex special chars
      regexStr += `\\${ch}`;
    } else {
      regexStr += ch;
    }
    i++;
  }
  return new RegExp(`^${regexStr}$`);
}

