    return new RegExp(`^${escapeRegexPart(parts[0])}$`);
  }

  let regexStr = "";
  for (let i = 0; i < parts.length; i++) {
    const part = parts[i];

    if (i === 0) {
      // Leading part before first **
      regexStr += escapeRegexPart(part);
    } else {
      // Each ** contributes "any characters including /"
      // If the previous literal part ended with / AND the next starts with /,
      // or if ** is at a path boundary, make it properly optional.
      //
      // Standard behavior: **/foo means "foo at any depth" (zero or more dirs)
      // So we use (?:.+/)? when ** is followed by / — making the dir prefix optional.
      const prevPart = parts[i - 1];
      const prevEndsSlash = prevPart.endsWith("/");
      const currStartsSlash = part.startsWith("/");

      if (prevEndsSlash || currStartsSlash) {
        // **/something or something/** — make cross-boundary optional
        // Use (?:.*/)?  so zero directories is allowed
        // Remove the leading slash from the current part (it's absorbed by the **)
        const trimmedPart = currStartsSlash ? part.slice(1) : part;
        regexStr += `(?:.*/)?${escapeRegexPart(trimmedPart)}`;
      } else {
        // ** not at a path boundary — treat as match-anything
        regexStr += `.*${escapeRegexPart(part)}`;
      }
    }
  }

  return new RegExp(`^${regexStr}$`);
}

