/**
 * Act Test Harness for PR Label Assigner
 *
 * Runs each test case through GitHub Actions via `act` and asserts:
 *   1. act exits with code 0
 *   2. Every job shows "Job succeeded"
 *   3. The LABELS_OUTPUT matches the expected value exactly
 *
 * Output is appended to act-result.txt with clear delimiters.
 */

import { spawnSync } from "child_process";
import { writeFileSync, appendFileSync, existsSync, unlinkSync } from "fs";

interface TestCase {
  name: string;
  changedFiles: string;
  expectedLabels: string; // comma-separated, order-independent check
  expectedLabelsSet: Set<string>;
}

// Test cases: input file lists and their expected label outputs
const TEST_CASES: TestCase[] = [
  {
    name: "docs-only",
    changedFiles: "docs/getting-started.md,docs/api/reference.md",
    expectedLabels: "documentation",
    expectedLabelsSet: new Set(["documentation"]),
  },
  {
    name: "api-files",
    changedFiles: "src/api/users.ts,src/api/products.ts",
    expectedLabels: "api,source",
    expectedLabelsSet: new Set(["api", "source"]),
  },
  {
    name: "test-files",
    changedFiles: "src/api/users.test.ts,src/components/Button.spec.tsx",
    expectedLabels: "tests,api,source",
    expectedLabelsSet: new Set(["tests", "api", "source"]),
  },
  {
    name: "mixed-pr",
    changedFiles:
      "docs/getting-started.md,src/api/users.ts,src/api/users.test.ts,.github/workflows/ci.yml",
    expectedLabels: "tests,ci/cd,api,source,documentation",
    expectedLabelsSet: new Set(["tests", "ci/cd", "api", "source", "documentation"]),
  },
  {
    name: "security-auth",
    changedFiles: "src/api/auth/login.ts,src/api/auth/middleware.ts",
    expectedLabels: "security,api,source",
    expectedLabelsSet: new Set(["security", "api", "source"]),
  },
  {
    name: "cicd-only",
    changedFiles: ".github/workflows/ci.yml,.github/dependabot.yml",
    expectedLabels: "ci/cd",
    expectedLabelsSet: new Set(["ci/cd"]),
  },
  {
    name: "infrastructure",
    changedFiles: "terraform/main.tf,terraform/variables.tf,infra/k8s/deploy.yaml",
    expectedLabels: "infrastructure",
    expectedLabelsSet: new Set(["infrastructure"]),
  },
  {
    name: "full-stack-pr",
    changedFiles:
      "src/api/auth/login.ts,src/components/LoginForm.tsx,src/components/LoginForm.test.tsx,docs/auth.md",
    expectedLabels: "security,tests,api,source,frontend,documentation",
    expectedLabelsSet: new Set(["security", "tests", "api", "source", "frontend", "documentation"]),
  },
];

// Workflow structure tests (validate YAML without running act)
interface WorkflowStructureTest {
  name: string;
  check: () => { passed: boolean; message: string };
}

const RESULT_FILE = "act-result.txt";
const WORKFLOW_FILE = ".github/workflows/pr-label-assigner.yml";
const PROJECT_DIR = process.cwd();

// Initialize result file
if (existsSync(RESULT_FILE)) {
  unlinkSync(RESULT_FILE);
}
writeFileSync(RESULT_FILE, `PR Label Assigner - Act Test Results\nDate: ${new Date().toISOString()}\n\n`);

function appendResult(text: string) {
  appendFileSync(RESULT_FILE, text + "\n");
  process.stdout.write(text + "\n");
}

function runAct(changedFiles: string, testCaseName: string): { exitCode: number; output: string } {
  appendResult(`\n${"=".repeat(60)}`);
  appendResult(`TEST CASE: ${testCaseName}`);
  appendResult(`CHANGED_FILES: ${changedFiles}`);
  appendResult("=".repeat(60));

  // Build act command
  // We use workflow_dispatch event with input parameters
  const actArgs = [
    "workflow_dispatch",
    "--rm",
    "-W", WORKFLOW_FILE,
    "--input", `changed_files=${changedFiles}`,
    "--input", `test_case=${testCaseName}`,
  ];

  appendResult(`Running: act ${actArgs.join(" ")}`);
  appendResult("");

  const result = spawnSync("act", actArgs, {
    cwd: PROJECT_DIR,
    encoding: "utf-8",
    timeout: 300_000, // 5 minute timeout
    maxBuffer: 10 * 1024 * 1024, // 10MB
  });

  const output = (result.stdout || "") + (result.stderr || "");
  appendResult(output);

  return {
    exitCode: result.status ?? 1,
    output,
  };
}

function parseLabelsFromOutput(output: string): Set<string> {
  // Look for "LABELS_OUTPUT=..." in the act output
  const match = output.match(/LABELS_OUTPUT=([^\r\n]*)/);
  if (!match) return new Set();
  return new Set(
    match[1]
      .split(",")
      .map((l) => l.trim())
      .filter((l) => l.length > 0)
  );
}

function checkJobSucceeded(output: string): boolean {
  return output.includes("Job succeeded");
}

// --- Workflow structure validation ---
function runStructureTests(): boolean {
  appendResult(`\n${"=".repeat(60)}`);
  appendResult("WORKFLOW STRUCTURE TESTS");
  appendResult("=".repeat(60));

  let allPassed = true;

  // Test 1: Workflow file exists
  const workflowExists = existsSync(WORKFLOW_FILE);
  appendResult(`[${workflowExists ? "PASS" : "FAIL"}] Workflow file exists: ${WORKFLOW_FILE}`);
  if (!workflowExists) allPassed = false;

  // Test 2: Script file exists
  const scriptExists = existsSync("src/index.ts");
  appendResult(`[${scriptExists ? "PASS" : "FAIL"}] Script file exists: src/index.ts`);
  if (!scriptExists) allPassed = false;

  // Test 3: Labeler module exists
  const labelerExists = existsSync("src/labeler.ts");
  appendResult(`[${labelerExists ? "PASS" : "FAIL"}] Labeler module exists: src/labeler.ts`);
  if (!labelerExists) allPassed = false;

  // Test 4: actionlint validation
  const lintResult = spawnSync("actionlint", [WORKFLOW_FILE], {
    cwd: PROJECT_DIR,
    encoding: "utf-8",
  });
  const lintPassed = lintResult.status === 0;
  appendResult(`[${lintPassed ? "PASS" : "FAIL"}] actionlint validation (exit code: ${lintResult.status})`);
  if (lintResult.stdout) appendResult(`  stdout: ${lintResult.stdout.trim()}`);
  if (lintResult.stderr) appendResult(`  stderr: ${lintResult.stderr.trim()}`);
  if (!lintPassed) allPassed = false;

  // Test 5: Workflow contains expected triggers
  const workflowContent = Bun.file(WORKFLOW_FILE);
  const workflowText = await workflowContent.text();
  const hasPushTrigger = workflowText.includes("push:");
  const hasPRTrigger = workflowText.includes("pull_request:");
  const hasWorkflowDispatch = workflowText.includes("workflow_dispatch:");
  const hasCheckout = workflowText.includes("actions/checkout@v4");
  const hasBunSetup = workflowText.includes("oven-sh/setup-bun");
  const hasBunTest = workflowText.includes("bun test");
  const hasBunRun = workflowText.includes("bun run src/index.ts");

  appendResult(`[${hasPushTrigger ? "PASS" : "FAIL"}] Workflow has push trigger`);
  if (!hasPushTrigger) allPassed = false;

  appendResult(`[${hasPRTrigger ? "PASS" : "FAIL"}] Workflow has pull_request trigger`);
  if (!hasPRTrigger) allPassed = false;

  appendResult(`[${hasWorkflowDispatch ? "PASS" : "FAIL"}] Workflow has workflow_dispatch trigger`);
  if (!hasWorkflowDispatch) allPassed = false;

  appendResult(`[${hasCheckout ? "PASS" : "FAIL"}] Workflow uses actions/checkout@v4`);
  if (!hasCheckout) allPassed = false;

  appendResult(`[${hasBunSetup ? "PASS" : "FAIL"}] Workflow sets up Bun`);
  if (!hasBunSetup) allPassed = false;

  appendResult(`[${hasBunTest ? "PASS" : "FAIL"}] Workflow runs bun test`);
  if (!hasBunTest) allPassed = false;

  appendResult(`[${hasBunRun ? "PASS" : "FAIL"}] Workflow runs bun run src/index.ts`);
  if (!hasBunRun) allPassed = false;

  return allPassed;
}

async function main() {
  appendResult("Starting PR Label Assigner Act Test Suite");
  appendResult(`Working directory: ${PROJECT_DIR}`);
  appendResult(`Timestamp: ${new Date().toISOString()}`);

  // Run workflow structure tests first
  const structurePassed = runStructureTests();

  // Run each test case through act
  let actPassCount = 0;
  let actFailCount = 0;
  const failures: string[] = [];

  for (const tc of TEST_CASES) {
    const { exitCode, output } = runAct(tc.changedFiles, tc.name);

    // Assert exit code
    const exitOk = exitCode === 0;
    appendResult(`\n--- Assertions for: ${tc.name} ---`);
    appendResult(`[${exitOk ? "PASS" : "FAIL"}] act exit code = 0 (got ${exitCode})`);

    // Assert job succeeded
    const jobOk = checkJobSucceeded(output);
    appendResult(`[${jobOk ? "PASS" : "FAIL"}] Job succeeded`);

    // Assert exact labels
    const actualLabels = parseLabelsFromOutput(output);
    const labelsMatch =
      actualLabels.size === tc.expectedLabelsSet.size &&
      [...tc.expectedLabelsSet].every((l) => actualLabels.has(l));

    appendResult(
      `[${labelsMatch ? "PASS" : "FAIL"}] Labels match expected`
    );
    appendResult(`  Expected: {${[...tc.expectedLabelsSet].sort().join(", ")}}`);
    appendResult(`  Got:      {${[...actualLabels].sort().join(", ")}}`);

    const testPassed = exitOk && jobOk && labelsMatch;
    if (testPassed) {
      actPassCount++;
    } else {
      actFailCount++;
      failures.push(tc.name);
    }
  }

  // Summary
  appendResult(`\n${"=".repeat(60)}`);
  appendResult("SUMMARY");
  appendResult("=".repeat(60));
  appendResult(`Structure tests: ${structurePassed ? "PASS" : "FAIL"}`);
  appendResult(`Act tests: ${actPassCount} passed, ${actFailCount} failed`);
  if (failures.length > 0) {
    appendResult(`Failed test cases: ${failures.join(", ")}`);
  }
  appendResult(`\nResults written to: ${RESULT_FILE}`);

  const overallPass = structurePassed && actFailCount === 0;
  appendResult(`\nOVERALL: ${overallPass ? "PASS" : "FAIL"}`);

  process.exit(overallPass ? 0 : 1);
}

main().catch((err) => {
  appendResult(`\nFatal error: ${err.message}`);
  process.exit(1);
});

