  // Test 2: Script file exists
  const scriptExists = existsSync("src/index.ts");
  appendResult(`[${scriptExists ? "PASS" : "FAIL"}] Script file exists: src/index.ts`);
  if (!scriptExists) allPassed = false;

  // Test 3: Labeler module exists
  const labelerExists = existsSync("src/labeler.ts");
  appendResult(`[${labelerExists ? "PASS" : "FAIL"}] Labeler module exists: src/labeler.ts`);
  if (!labelerExists) allPassed = false;

  // Test 4: actionlint validation
  const lintResult = spawnSync("actionlint", [WORKFLOW_FILE], {
    cwd: PROJECT_DIR,
    encoding: "utf-8",
  });
  const lintPassed = lintResult.status === 0;
  appendResult(`[${lintPassed ? "PASS" : "FAIL"}] actionlint validation (exit code: ${lintResult.status})`);
  if (lintResult.stdout) appendResult(`  stdout: ${lintResult.stdout.trim()}`);
  if (lintResult.stderr) appendResult(`  stderr: ${lintResult.stderr.trim()}`);
  if (!lintPassed) allPassed = false;

  // Test 5: Workflow contains expected triggers
  const workflowContent = Bun.file(WORKFLOW_FILE);
  const workflowText = await workflowContent.text();
  const hasPushTrigger = workflowText.includes("push:");
  const hasPRTrigger = workflowText.includes("pull_request:");
  const hasWorkflowDispatch = workflowText.includes("workflow_dispatch:");
  const hasCheckout = workflowText.includes("actions/checkout@v4");
  const hasBunSetup = workflowText.includes("oven-sh/setup-bun");
  const hasBunTest = workflowText.includes("bun test");
  const hasBunRun = workflowText.includes("bun run src/index.ts");

  appendResult(`[${hasPushTrigger ? "PASS" : "FAIL"}] Workflow has push trigger`);
  if (!hasPushTrigger) allPassed = false;

  appendResult(`[${hasPRTrigger ? "PASS" : "FAIL"}] Workflow has pull_request trigger`);
  if (!hasPRTrigger) allPassed = false;

  appendResult(`[${hasWorkflowDispatch ? "PASS" : "FAIL"}] Workflow has workflow_dispatch trigger`);
  if (!hasWorkflowDispatch) allPassed = false;

  appendResult(`[${hasCheckout ? "PASS" : "FAIL"}] Workflow uses actions/checkout@v4`);
  if (!hasCheckout) allPassed = false;

  appendResult(`[${hasBunSetup ? "PASS" : "FAIL"}] Workflow sets up Bun`);
  if (!hasBunSetup) allPassed = false;

  appendResult(`[${hasBunTest ? "PASS" : "FAIL"}] Workflow runs bun test`);
  if (!hasBunTest) allPassed = false;

  appendResult(`[${hasBunRun ? "PASS" : "FAIL"}] Workflow runs bun run src/index.ts`);
  if (!hasBunRun) allPassed = false;

  return allPassed;
}

async function main() {
  appendResult("Starting PR Label Assigner Act Test Suite");
  appendResult(`Working directory: ${PROJECT_DIR}`);
  appendResult(`Timestamp: ${new Date().toISOString()}`);

  // Run workflow structure tests first
  const structurePassed = runStructureTests();

  // Run each test case through act
  let actPassCount = 0;
  let actFailCount = 0;
  const failures: string[] = [];

  for (const tc of TEST_CASES) {
    const { exitCode, output } = runAct(tc.changedFiles, tc.name);

    // Assert exit code
    const exitOk = exitCode === 0;
    appendResult(`\n--- Assertions for: ${tc.name} ---`);
    appendResult(`[${exitOk ? "PASS" : "FAIL"}] act exit code = 0 (got ${exitCode})`);

    // Assert job succeeded
    const jobOk = checkJobSucceeded(output);
    appendResult(`[${jobOk ? "PASS" : "FAIL"}] Job succeeded`);

    // Assert exact labels
    const actualLabels = parseLabelsFromOutput(output);
    const labelsMatch =
      actualLabels.size === tc.expectedLabelsSet.size &&
      [...tc.expectedLabelsSet].every((l) => actualLabels.has(l));

    appendResult(
      `[${labelsMatch ? "PASS" : "FAIL"}] Labels match expected`
    );
    appendResult(`  Expected: {${[...tc.expectedLabelsSet].sort().join(", ")}}`);
    appendResult(`  Got:      {${[...actualLabels].sort().join(", ")}}`);

    const testPassed = exitOk && jobOk && labelsMatch;
    if (testPassed) {
      actPassCount++;
    } else {
      actFailCount++;
      failures.push(tc.name);
    }
  }

  // Summary
  appendResult(`\n${"=".repeat(60)}`);
  appendResult("SUMMARY");
  appendResult("=".repeat(60));
  appendResult(`Structure tests: ${structurePassed ? "PASS" : "FAIL"}`);
  appendResult(`Act tests: ${actPassCount} passed, ${actFailCount} failed`);
  if (failures.length > 0) {
    appendResult(`Failed test cases: ${failures.join(", ")}`);
  }
  appendResult(`\nResults written to: ${RESULT_FILE}`);

  const overallPass = structurePassed && actFailCount === 0;
  appendResult(`\nOVERALL: ${overallPass ? "PASS" : "FAIL"}`);

  process.exit(overallPass ? 0 : 1);
}

main().catch((err) => {
  appendResult(`\nFatal error: ${err.message}`);
  process.exit(1);
});

